#include <bits/stdc++.h>
#define ll long long
using namespace std;
static char buf[100000], * pa(buf), * pb(buf);
#define gc pa == pb && (pb = (pa = buf) + fread(buf, 1, 100000, stdin), pa == pb) ? EOF : *pa++
inline int read(){
	int num=0,f=1;char c=gc;
	while(c<'0'||c>'9'){if(c=='-')f=-1;c=gc;}
	while(c>='0'&&c<='9'){num=(num<<3)+(num<<1)+(c&15);c=gc;}
	return num*f;
}
inline void write(ll x){
	if(x<0)putchar('-'),x=-x;
	if(x>9)write(x/10);
	putchar(x%10+'0');
}
int n,a[1000005],d;
ll ans;
int main(void)
{
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	n=read(),d=read();
	for(int i=1;i<=n;++i)a[i]=read();
	sort(a+1,a+n+1);
	int r=2;
	for(int l=1;l<n;++l)
	{
		while(a[r]-a[l]<=d&&r<=n)++r;
		ans+=r-l-1;
	}
	write(ans);
	return false;
}
